function createMinimalAmsdosHeader(type: string, start: number, length: number) {
	return {
		typeString: type,
		start: start,
		length: length
	} as AmsdosHeader;
}

function readFilesFromDiskImage(disk: DiskImage) {
	const result: string[] = [],
		dir = disk.readDirectory(),
		entries = Object.keys(dir);

	for (let i = 0; i < entries.length; i += 1) {
		const name = entries[i];
		let data = disk.readFile(dir[name]);

		if (data) {
			let headerEntry = DiskImage.parseAmsdosHeader(data);

			if (headerEntry) {
				data = data.substring(0x80); // remove header
				if (headerEntry.typeString === "P") { // protected BASIC?
					data = DiskImage.unOrProtectData(data);
					data = new BasicTokenizer().decode(data);
				} else if (headerEntry.typeString === "T") { // tokenized BASIC?
					data = new BasicTokenizer().decode(data);
				}
			} else {
				headerEntry = createMinimalAmsdosHeader("A", 0, data.length);
			}

			const headerString = JSON.stringify(headerEntry);

			result.push(name + " -- " + headerString + " -- " + data);
		}
	}
	return result.join(" --- ");
}

function extractFirstFileFromZip(key: string) {
	const parts = Utils.split2(key, ","),
		compressed = Utils.atob(parts[1]), // decode base64
		zip = new ZipFile({
			data: Utils.string2Uint8Array(compressed),
			zipName: "name"
		}),
		firstFileInZip = Object.keys(zip.getZipDirectory())[0],
		uncompressed = zip.readData(firstFileInZip);

	return uncompressed;
}


QUnit.module("DiskImage: Read files tests", function (hooks) {
	function runTestsFor(category: string, tests: TestsType, assert?: Assert, results?: ResultType) {
		for (const key in tests) {
			if (tests.hasOwnProperty(key)) {
				const uncompressed = extractFirstFileFromZip(key),
					disk = new DiskImage({
						data: uncompressed,
						diskName: "name",
						quiet: true
					}),
					expected = tests[key];
				let result: string;

				try {
					result = readFilesFromDiskImage(disk);
				} catch (e) {
					result = String(e);
					if (result !== expected) { // output in console only if error not expected
						Utils.console.error(e);
					}
				}

				if (results) {
					results[category].push(TestHelper.stringInQuotes(key) + ": " + TestHelper.stringInQuotes(result));
				}

				if (assert) {
					const message = "uncompressed DSK: " + uncompressed.length;

					assert.strictEqual(result, expected, message);
				}
			}
		}
	}

	TestHelper.generateAllTests(allTests, runTestsFor, hooks);
});


function createCodeGeneratorToken() {
	const basicParser = new BasicParser({
			quiet: true,
			keepTokens: true,
			keepBrackets: true,
			keepColons: true,
			keepDataComma: true
		}),
		basicLexer = new BasicLexer({
			keywords: basicParser.getKeywords(),
			keepWhiteSpace: true,
			quiet: true
		});

	return new CodeGeneratorToken({
		quiet: true,
		lexer: basicLexer,
		parser: basicParser
	});
}

// check also: https://stackoverflow.com/questions/40031688/javascript-arraybuffer-to-hex
// https://gist.github.com/taniarascia/7ff2e83577d83b85a421ab36ab2ced84
// https://gist.github.com/igorgatis/d294fe714a4f523ac3a3

function fnBin2Hex(bin: string) {
	const hexList = [],
		asciiList = [],
		lineList = [];

	for (let i = 0; i < bin.length; i += 1) {
		const charCode = bin.charCodeAt(i);

		hexList.push(charCode.toString(16).toUpperCase().padStart(2, "0"));
		asciiList.push(charCode >= 0x20 ? bin.charAt(i) : ".");
		if (i % 16 === 15) {
			const addr = (i - 15).toString(16).toUpperCase().padStart(4, "0");

			lineList.push(addr + "  " + hexList.join(" ") + "  " + asciiList.join(""));
			hexList.length = 0;
			asciiList.length = 0;
		}
	}
	if (hexList.length) {
		lineList.push(hexList.join(" ") + "  " + asciiList.join(""));
	}

	return lineList.join("\n");
}


QUnit.module("DiskImage: Write files tests", function (hooks) {
	function runTestsFor(category: string, tests: TestsType, assert?: Assert, results?: ResultType) {
		for (const key in tests) {
			if (tests.hasOwnProperty(key)) {
				if (category === "data" || category === "system") {
					const input = tests[key],
						fileInfos = input.split(" --- "),
						diskImage = new DiskImage({
							quiet: true,
							data: ""
						});

					diskImage.setOptions({
						diskName: "test",
						data: diskImage.formatImage(category)
					});

					const codeGeneratorToken = createCodeGeneratorToken();

					for (let i = 0; i < fileInfos.length; i += 1) {
						const fileInfo = fileInfos[i],
							[name, metaJson, data1] = fileInfo.split(" -- "), // eslint-disable-line array-element-newline
							headerEntry = JSON.parse(metaJson) as AmsdosHeader;

						let data = data1;

						// eslint-disable-next-line max-depth
						if (headerEntry.typeString === "P") { // protected BASIC?
							const output = codeGeneratorToken.generate(data);

							data = output.error ? String(output.error) : output.text;
							data = DiskImage.unOrProtectData(data);
						} else if (headerEntry.typeString === "T") { // tokenized BASIC?
							const output2 = codeGeneratorToken.generate(data);

							data = output2.error ? String(output2.error) : output2.text;
						} else if (headerEntry.typeString === "B") { // Binary
							// take it as it is
						} else if (headerEntry.typeString === "A") { // ASCII
							// take it as it is
						} else {
							Utils.console.error("runTestsFor: Unknon file type:", headerEntry.typeString);
						}

						if (headerEntry.typeString !== "A") {
							if (data.length !== headerEntry.length) {
								Utils.console.warn("runTestsFor: " + name + ": Need to adapt length:", data.length);
								headerEntry.length = data.length;
								headerEntry.pseudoLen = data.length;
							}
							const header = DiskImage.createAmsdosHeader(headerEntry),
								headerString = DiskImage.combineAmsdosHeader(header);

							data = headerString + data;
						}

						diskImage.writeFile(name, data);
					}

					const result = diskImage.stripEmptyTracks(),
						uncompressed = extractFirstFileFromZip(key),
						expected = uncompressed;

					if (results) {
						results[category].push(TestHelper.stringInQuotes(key) + ": " + TestHelper.stringInQuotes(result));
					}

					if (assert) {
						const message = category + " DSK";

						if (Utils.debug > 5) {
							Utils.console.debug(message + ": result: ", fnBin2Hex(result));
							Utils.console.debug(message + ": expected: ", fnBin2Hex(expected));
						}

						// compare disk images
						assert.strictEqual(fnBin2Hex(result), fnBin2Hex(expected), message);

						// read back files anf compare
						const expected2 = input;
						let result2 = "";

						try {
							result2 = readFilesFromDiskImage(diskImage);
						} catch (e) {
							result2 = String(e);
						}
						assert.strictEqual(result2, expected2, message);
					}
				} else if (assert) {
					assert.expect(0); // not testing this
				}
			}
		}
	}
	TestHelper.generateAllTests(allTests, runTestsFor, hooks);
});


